/**
 * Live public site and support defaults.
 * Override with VITE_PUBLIC_SITE_URL, VITE_SUPPORT_EMAIL, VITE_API_URL in .env
 */

export const PUBLIC_SITE_ORIGIN = (import.meta.env.VITE_PUBLIC_SITE_URL || 'https://apimstec.com').replace(
  /\/$/,
  '',
)

/** Inbound contact address for form deliveries (override with VITE_SUPPORT_EMAIL). Match this in your CMS mail settings. */
export const SUPPORT_EMAIL = import.meta.env.VITE_SUPPORT_EMAIL || 'apimstecofficial@gmail.com'

/** Production CMS/API host when VITE_API_URL is not set at build time. */
export const DEFAULT_CMS_API_ORIGIN = 'https://portal.apimstec.com'
